// 4개 입력 소스를 하나의 JSON 객체로 병합
// input 0: anomaly_log, input 1: daily_summary, input 2: production_week, input 3: line_master
const anomalyLog = $input("Read anomaly_log").all().map(i => i.json);
const dailySummary = $input("Read daily_summary").all().map(i => i.json);
const productionWeek = $input("Read production_week").all().map(i => i.json);
const lineMaster = $input("Read line_master").all().map(i => i.json);

return [{
  json: {
    anomalyLog,
    dailySummary,
    productionWeek,
    lineMaster
  }
}];

// 워크플로 D — Code Node 1: 데이터 로드 + 도구 함수 정의 + 마스킹
// 입력: Google Sheets에서 읽은 anomaly_log, daily_summary, production_week, line_master
// 출력: Agent에게 보낼 tools 정의 + 마스킹된 데이터 + System Prompt

const input = items[0].json;
const anomalyLog = input.anomalyLog || [];
const dailySummary = input.dailySummary || [];
const productionWeek = input.productionWeek || [];
const lineMaster = input.lineMaster || [];

// --- 날짜 계산 ---
const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(yesterday.getDate() - 1);
const yesterdayStr = yesterday.toISOString().slice(0, 10);

// --- 마스킹 사전 ---
const maskDict = {};
const reverseDict = {};
lineMaster.forEach((lm, i) => {
  const lineCode = `LINE_${String.fromCharCode(65 + i)}`;
  const productCode = `PROD_${String(i + 1).padStart(2, '0')}`;
  const teamCode = `TEAM_${lm['팀'].replace(/[^0-9]/g, '')}`;
  maskDict[lm['라인명']] = lineCode;
  maskDict[lm['품목']] = productCode;
  maskDict[lm['팀']] = teamCode;
  reverseDict[lineCode] = lm['라인명'];
  reverseDict[productCode] = lm['품목'];
  reverseDict[teamCode] = lm['팀'];
});

function maskText(text) {
  if (typeof text !== 'string') return text;
  let masked = text;
  const keys = Object.keys(maskDict).sort((a, b) => b.length - a.length);
  for (const k of keys) { masked = masked.split(k).join(maskDict[k]); }
  return masked;
}

function maskObj(obj) {
  const result = {};
  for (const [k, v] of Object.entries(obj)) {
    result[k] = typeof v === 'string' ? maskText(v) : v;
  }
  return result;
}

// --- 마스킹된 데이터 준비 ---
const maskedAnomalyLog = anomalyLog.map(maskObj);
const maskedDailySummary = dailySummary.map(maskObj);
const maskedProductionWeek = productionWeek.map(maskObj);
const maskedLineMaster = lineMaster.map((lm, i) => ({
  라인ID: lm['라인ID'],
  라인명: maskDict[lm['라인명']] || lm['라인명'],
  팀: maskDict[lm['팀']] || lm['팀'],
  품목: maskDict[lm['품목']] || lm['품목'],
  시간당목표: lm['시간당목표'],
  정상불량률: lm['정상불량률']
}));

// --- Claude API Tool 정의 ---
const tools = [
  {
    name: "get_anomaly_log",
    description: "이상 이력을 조회합니다. 날짜, 심각도, 라인ID로 필터링할 수 있습니다.",
    input_schema: {
      type: "object",
      properties: {
        date: { type: "string", description: "조회할 날짜 (YYYY-MM-DD). 미지정 시 어제" },
        severity: { type: "string", description: "심각도 필터 (심각/중간/낮음). 미지정 시 전체" },
        line_id: { type: "string", description: "라인ID 필터 (예: L03). 미지정 시 전체" }
      },
      required: []
    }
  },
  {
    name: "get_daily_summary",
    description: "일별 요약을 조회합니다. 날짜, 팀으로 필터링할 수 있습니다.",
    input_schema: {
      type: "object",
      properties: {
        date: { type: "string", description: "조회할 날짜 (YYYY-MM-DD). 미지정 시 어제" },
        team: { type: "string", description: "팀 필터 (예: TEAM_1). 미지정 시 전체" }
      },
      required: []
    }
  },
  {
    name: "get_line_master",
    description: "라인/팀 구성 정보를 조회합니다.",
    input_schema: {
      type: "object",
      properties: {},
      required: []
    }
  },
  {
    name: "get_hourly_detail",
    description: "시간별 생산 상세 데이터를 조회합니다. 날짜, 라인ID로 필터링할 수 있습니다.",
    input_schema: {
      type: "object",
      properties: {
        date: { type: "string", description: "조회할 날짜 (YYYY-MM-DD). 미지정 시 어제" },
        line_id: { type: "string", description: "라인ID 필터 (예: L03). 미지정 시 전체" }
      },
      required: []
    }
  }
];

// --- System Prompt ---
const systemPrompt = `당신은 제조 현장 일일 리포트를 작성하는 AI Agent입니다.
제공된 도구를 사용해 어제(${yesterdayStr})의 생산 데이터를 조회하고 분석하세요.

도구 사용 규칙:
- 먼저 get_anomaly_log로 어제 이상 건수를 파악하세요.
- 심각도와 건수에 따라 추가 조회 깊이를 결정하세요.
- 불필요한 도구 호출은 하지 마세요.
- 모든 라인명과 품목명은 제공된 코드(LINE_A, PROD_01 등)로 표기하세요.

리포트 깊이 기준:
- 심각 0건 + 중간 2건 이하 → 간단 (도구 1~2회)
- 심각 1~2건 또는 중간 3건+ → 보통 (도구 3~4회)
- 심각 3건+ 또는 악화 추세 → 상세 (도구 5~6회, 경영진 CC)

반드시 아래 JSON 형식으로 응답하세요:
{
  "report_level": "간단/보통/상세",
  "cc_management": true/false,
  "summary": "한 줄 요약",
  "sections": {
    "핵심_경고": "심각/악화 건 상세 (없으면 '없음')",
    "추세_분석": "최근 7일 추이 (보통/상세만)",
    "팀별_현황": "팀별 달성률/불량률 요약",
    "기타_이상": "중간/낮음 건 요약",
    "권장_조치": "조치 사항 정리"
  },
  "recommendations": ["권장 조치 1", "권장 조치 2"]
}`;

return [{ json: {
  tools,
  systemPrompt,
  yesterdayStr,
  maskedAnomalyLog,
  maskedDailySummary,
  maskedProductionWeek,
  maskedLineMaster,
  reverseDict
} }];

// 워크플로 D — Code Node 2: AI Agent 루프
// 입력: d_code1에서 전달된 tools, systemPrompt, 마스킹된 데이터
// 출력: Agent 최종 리포트 또는 폴백 리포트

const input = items[0].json;
const tools = input.tools;
const systemPrompt = input.systemPrompt;
const yesterdayStr = input.yesterdayStr;
const maskedAnomalyLog = input.maskedAnomalyLog;
const maskedDailySummary = input.maskedDailySummary;
const maskedProductionWeek = input.maskedProductionWeek;
const maskedLineMaster = input.maskedLineMaster;
const reverseDict = input.reverseDict;

const MAX_TOOL_CALLS = 8;
const API_TIMEOUT = 60000;

// --- API 키를 워크플로 Static Data에서 가져오기 ---
// n8n UI에서 Settings > Static Data > global에 {"anthropic_api_key": "sk-ant-..."} 설정 필요
const staticData = $getWorkflowStaticData('global');
const apiKey = staticData.anthropic_api_key || '';

if (!apiKey) {
  return [{ json: {
    agentSuccess: false,
    finalReport: null,
    toolCallCount: 0,
    reverseDict,
    yesterdayStr,
    error: 'anthropic_api_key가 워크플로 Static Data에 설정되지 않았습니다. Settings > Static Data에 {"anthropic_api_key": "sk-ant-..."}를 추가하세요.'
  } }];
}

// --- 도구 실행 함수 ---
function executeTool(toolName, toolInput) {
  try {
    if (toolName === 'get_anomaly_log') {
      let results = maskedAnomalyLog;
      const date = toolInput.date || yesterdayStr;
      results = results.filter(r => r['날짜'] === date);
      if (toolInput.severity) results = results.filter(r => r.severity === toolInput.severity);
      if (toolInput.line_id) results = results.filter(r => r['라인ID'] === toolInput.line_id);
      return JSON.stringify({ count: results.length, data: results.slice(0, 50) });
    }

    if (toolName === 'get_daily_summary') {
      let results = maskedDailySummary;
      const date = toolInput.date || yesterdayStr;
      results = results.filter(r => r['날짜'] === date);
      if (toolInput.team) results = results.filter(r => r['팀'] === toolInput.team);
      return JSON.stringify({ count: results.length, data: results });
    }

    if (toolName === 'get_line_master') {
      return JSON.stringify({ count: maskedLineMaster.length, data: maskedLineMaster });
    }

    if (toolName === 'get_hourly_detail') {
      let results = maskedProductionWeek;
      const date = toolInput.date || yesterdayStr;
      results = results.filter(r => r['날짜'] === date);
      if (toolInput.line_id) results = results.filter(r => r['라인ID'] === toolInput.line_id);
      return JSON.stringify({ count: results.length, data: results.slice(0, 120) });
    }

    return JSON.stringify({ error: `알 수 없는 도구: ${toolName}` });
  } catch (e) {
    return JSON.stringify({ error: `도구 실행 실패: ${e.message}` });
  }
}

// --- Agent 루프 ---
const messages = [{ role: "user", content: `어제(${yesterdayStr}) 일일 리포트를 작성해주세요.` }];
let toolCallCount = 0;
let agentSuccess = false;
let finalReport = null;

try {
  for (let iteration = 0; iteration < MAX_TOOL_CALLS + 2; iteration++) {
    const requestBody = {
      model: "claude-sonnet-4-20250514",
      max_tokens: 3000,
      system: systemPrompt,
      tools: tools,
      messages: messages
    };

    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: requestBody,
      timeout: API_TIMEOUT,
      json: true
    });

    if (response.stop_reason === 'tool_use') {
      const assistantContent = response.content;
      messages.push({ role: "assistant", content: assistantContent });

      const toolResults = [];
      for (const block of assistantContent) {
        if (block.type === 'tool_use') {
          toolCallCount++;
          if (toolCallCount > MAX_TOOL_CALLS) {
            toolResults.push({
              type: "tool_result",
              tool_use_id: block.id,
              content: JSON.stringify({ error: "도구 호출 횟수 초과 (최대 8회). 현재까지 데이터로 리포트를 작성하세요." })
            });
          } else {
            const result = executeTool(block.name, block.input);
            toolResults.push({
              type: "tool_result",
              tool_use_id: block.id,
              content: result
            });
          }
        }
      }

      messages.push({ role: "user", content: toolResults });

      if (toolCallCount > MAX_TOOL_CALLS) continue;
    } else if (response.stop_reason === 'end_turn') {
      const textBlock = response.content.find(b => b.type === 'text');
      if (textBlock) {
        finalReport = textBlock.text;
        agentSuccess = true;
      }
      break;
    } else {
      break;
    }
  }
} catch (e) {
  agentSuccess = false;
  finalReport = null;
}

// --- 결과 전달 ---
return [{ json: {
  agentSuccess,
  finalReport,
  toolCallCount,
  reverseDict,
  yesterdayStr
} }];

// 워크플로 D — Code Node 3: 리포트 파싱 + 언마스킹 + 이메일 생성
// 입력: Agent 루프 결과 (성공 시 JSON 리포트)
// 출력: 이메일 제목 + 본문 + CC 여부

const input = items[0].json;
const agentSuccess = input.agentSuccess;
const finalReport = input.finalReport;
const reverseDict = input.reverseDict || {};
const yesterdayStr = input.yesterdayStr;
const toolCallCount = input.toolCallCount || 0;

function unmask(text) {
  if (typeof text !== 'string') return text;
  let result = text;
  const keys = Object.keys(reverseDict).sort((a, b) => b.length - a.length);
  for (const code of keys) { result = result.split(code).join(reverseDict[code]); }
  return result;
}

let emailSubject = '';
let emailBody = '';
let ccManagement = false;

if (agentSuccess && finalReport) {
  // --- JSON 파싱 시도 ---
  let report = null;
  try {
    const cleaned = finalReport.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    report = JSON.parse(cleaned);
  } catch (e) {
    report = null;
  }

  if (report && report.summary) {
    // 파싱 성공: 구조화된 리포트
    ccManagement = report.cc_management || false;
    const level = report.report_level || '보통';
    const levelEmoji = level === '상세' ? '🔴' : level === '보통' ? '🟡' : '🟢';

    emailSubject = `[일일 리포트] ${levelEmoji} ${unmask(report.summary)} (${yesterdayStr})`;

    const parts = [];
    parts.push(`<h2>${levelEmoji} 일일 생산 리포트 — ${yesterdayStr}</h2>`);
    parts.push(`<p><b>리포트 수준:</b> ${level} | <b>도구 호출:</b> ${toolCallCount}회</p>`);
    parts.push(`<p><b>요약:</b> ${unmask(report.summary)}</p>`);
    parts.push('<hr>');

    if (report.sections) {
      const sectionNames = {
        '핵심_경고': '🚨 핵심 경고',
        '추세_분석': '📈 추세 분석',
        '팀별_현황': '👥 팀별 현황',
        '기타_이상': 'ℹ️ 기타 이상',
        '권장_조치': '✅ 권장 조치'
      };
      for (const [key, title] of Object.entries(sectionNames)) {
        const content = report.sections[key];
        if (content && content !== '없음') {
          parts.push(`<h3>${title}</h3>`);
          parts.push(`<p>${unmask(content)}</p>`);
        }
      }
    }

    if (report.recommendations && report.recommendations.length > 0) {
      parts.push('<h3>📋 권장 조치 목록</h3>');
      parts.push('<ol>' + report.recommendations.map(r => `<li>${unmask(r)}</li>`).join('') + '</ol>');
    }

    parts.push(`<hr><p style="color:#888;font-size:12px;">AI Agent 생성 | ${new Date().toISOString()}</p>`);
    emailBody = parts.join('\n');
  } else {
    // 파싱 실패: 텍스트 그대로 사용
    emailSubject = `[일일 리포트] ${yesterdayStr} (텍스트 형식)`;
    emailBody = `<h2>일일 생산 리포트 — ${yesterdayStr}</h2><p><i>AI 응답을 JSON으로 파싱하지 못하여 원문을 포함합니다.</i></p><hr><pre>${unmask(finalReport)}</pre><hr><p style="color:#888;font-size:12px;">AI Agent 생성 (파싱 실패) | ${new Date().toISOString()}</p>`;
  }
} else {
  // 폴백 (이 노드가 FALSE 브랜치에서도 호출될 수 있음)
  emailSubject = `[일일 리포트] ⚠️ 자동 생성 실패 — 폴백 리포트 (${yesterdayStr})`;
  emailBody = `<h2>⚠️ 일일 생산 리포트 — ${yesterdayStr}</h2><p><b>AI Agent 리포트 생성에 실패하여 폴백 리포트를 발송합니다.</b></p><p>상세 분석은 Power BI 대시보드 또는 Google Sheets anomaly_log를 직접 확인해주세요.</p><hr><h3>확인 필요 사항</h3><ul><li>production_results 시트의 anomaly_log 탭에서 어제 이상 건 확인</li><li>hourly_summary 탭에서 팀별 달성률 확인</li><li>Claude API 키 및 네트워크 상태 확인</li></ul><hr><p style="color:#888;font-size:12px;">폴백 리포트 | ${new Date().toISOString()}</p>`;
}

return [{ json: { emailSubject, emailBody, ccManagement, sendEmail: true } }];

// 워크플로 D — Code Node 3 (폴백): 폴백 리포트 생성
// 입력: Agent 루프 실패 결과
// 출력: 폴백 이메일 제목 + 본문

const input = items[0].json;
const reverseDict = input.reverseDict || {};
const yesterdayStr = input.yesterdayStr;

function unmask(text) {
  if (typeof text !== 'string') return text;
  let result = text;
  const keys = Object.keys(reverseDict).sort((a, b) => b.length - a.length);
  for (const code of keys) { result = result.split(code).join(reverseDict[code]); }
  return result;
}

const emailSubject = `[일일 리포트] ⚠️ 자동 생성 실패 — 폴백 리포트 (${yesterdayStr})`;
const emailBody = `<h2>⚠️ 일일 생산 리포트 — ${yesterdayStr}</h2>
<p><b>AI Agent 리포트 생성에 실패하여 폴백 리포트를 발송합니다.</b></p>
<p>상세 분석은 Power BI 대시보드 또는 Google Sheets anomaly_log를 직접 확인해주세요.</p>
<hr>
<h3>확인 필요 사항</h3>
<ul>
  <li>production_results 시트의 anomaly_log 탭에서 어제 이상 건 확인</li>
  <li>hourly_summary 탭에서 팀별 달성률 확인</li>
  <li>Claude API 키 및 네트워크 상태 확인</li>
</ul>
<hr>
<p style="color:#888;font-size:12px;">폴백 리포트 | ${new Date().toISOString()}</p>`;

return [{ json: { emailSubject, emailBody, ccManagement: false, sendEmail: true } }];
